/**
 * Dashboard utility functions for real-time data handling
 */

/**
 * Fixed-size buffer that maintains the N most recent values
 * Never exceeds capacity N, always contains N most recent values in order
 */
export class FixedSizeBuffer<T> {
  private buffer: T[] = [];
  private capacity: number;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error('Buffer capacity must be positive');
    }
    this.capacity = capacity;
  }

  /**
   * Append a value to the buffer
   * If buffer is at capacity, removes the oldest value
   */
  append(value: T): void {
    this.buffer.push(value);
    if (this.buffer.length > this.capacity) {
      this.buffer.shift();
    }
  }

  /**
   * Get all values in the buffer
   */
  getValues(): T[] {
    return [...this.buffer];
  }

  /**
   * Get the current size of the buffer
   */
  size(): number {
    return this.buffer.length;
  }

  /**
   * Clear the buffer
   */
  clear(): void {
    this.buffer = [];
  }
}

/**
 * Throttle function that emits at most one event per T-millisecond window
 * Returns a function that can be called multiple times but only executes the callback
 * at most once per throttle interval
 */
export function createThrottle<T extends any[]>(
  callback: (...args: T) => void,
  intervalMs: number
): (...args: T) => void {
  let lastExecutionTime = 0;
  let pendingArgs: T | null = null;
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  return (...args: T) => {
    const now = Date.now();
    const timeSinceLastExecution = now - lastExecutionTime;

    if (timeSinceLastExecution >= intervalMs) {
      // Enough time has passed, execute immediately
      callback(...args);
      lastExecutionTime = now;
      pendingArgs = null;
      if (timeoutId) {
        clearTimeout(timeoutId);
        timeoutId = null;
      }
    } else {
      // Not enough time has passed, store args and schedule execution
      pendingArgs = args;
      if (!timeoutId) {
        const remainingTime = intervalMs - timeSinceLastExecution;
        timeoutId = setTimeout(() => {
          if (pendingArgs) {
            callback(...pendingArgs);
            lastExecutionTime = Date.now();
          }
          timeoutId = null;
          pendingArgs = null;
        }, remainingTime);
      }
    }
  };
}

/**
 * Event buffer for storing events during disconnection and replaying on reconnect
 * Maintains order and allows replay of all buffered events
 */
export class EventBuffer<T> {
  private buffer: T[] = [];

  /**
   * Add an event to the buffer
   */
  add(event: T): void {
    this.buffer.push(event);
  }

  /**
   * Get all buffered events in order and clear the buffer
   */
  drain(): T[] {
    const events = [...this.buffer];
    this.buffer = [];
    return events;
  }

  /**
   * Get the current number of buffered events
   */
  size(): number {
    return this.buffer.length;
  }

  /**
   * Clear all buffered events
   */
  clear(): void {
    this.buffer = [];
  }
}

/**
 * Calculate percentage change between two values
 * Handles zero previous value by returning 0
 * Formula: ((current - previous) / previous) * 100
 */
export function calculatePercentageChange(current: number, previous: number): number {
  if (previous === 0) {
    // If previous is 0, return 0 (cannot calculate percentage change from zero)
    return 0;
  }
  return ((current - previous) / previous) * 100;
}

