     * the buffer length should never exceed N, and the buffer should always contain the N
     * most recently appended values in order.
     */
    it('should never exceed capacity N and contain N most recent values', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 1, max: 100 }),
          fc.array(fc.integer(), { minLength: 1, maxLength: 200 }),
          (capacity, values) => {
            const buffer = new FixedSizeBuffer(capacity);

            // Append all values
            for (const value of values) {
              buffer.append(value);
            }

            const result = buffer.getValues();

            // Property 1a: Buffer size never exceeds capacity
            expect(result.length).toBeLessThanOrEqual(capacity);

            // Property 1b: Buffer contains the N most recent values
            const expectedValues = values.slice(-capacity);
            expect(result).toEqual(expectedValues);
          }
        )
      );
    });

    it('should maintain order of appended values', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 1, max: 50 }),
          fc.array(fc.integer(), { minLength: 1, maxLength: 100 }),
          (capacity, values) => {
            const buffer = new FixedSizeBuffer(capacity);

            for (const value of values) {
              buffer.append(value);
            }

            const result = buffer.getValues();
            const expected = values.slice(-capacity);

            // Values should be in the same order as appended
            for (let i = 0; i < result.length; i++) {
              expect(result[i]).toBe(expected[i]);
            }
          }
        )
      );
    });

    it('should handle edge case of single capacity', () => {
      fc.assert(
        fc.property(
