      const callTimes: number[] = [];

      const throttled = createThrottle(() => {
        callCount++;
        callTimes.push(Date.now());
      }, throttleInterval);

      const startTime = Date.now();

      // Call immediately
      throttled();

      // Call after 10ms (within throttle window)
      setTimeout(() => throttled(), 10);

      // Call after 60ms (outside throttle window)
