/**
 * Property 4: Message Direction Determines Alignment
 * For any message, if direction is OUTBOUND then alignment is 'right',
 * and if direction is INBOUND then alignment is 'left'.
 */
function getMessageAlignment(direction: 'INBOUND' | 'OUTBOUND'): 'left' | 'right' {
  return direction === 'OUTBOUND' ? 'right' : 'left';
}

/**
 * Property 5: Media Type to Renderer Mapping
 * For any message with a mediaType field, the renderer selection function
 * should return: 'thumbnail' for IMAGE, 'file-card' for DOCUMENT,
 * 'waveform' for AUDIO, and 'video-player' for VIDEO.
 */
function getMediaRenderer(
  mediaType: 'image' | 'document' | 'audio' | 'video'
): 'thumbnail' | 'file-card' | 'waveform' | 'video-player' {
  switch (mediaType) {
    case 'image':
      return 'thumbnail';
    case 'document':
      return 'file-card';
    case 'audio':
      return 'waveform';
    case 'video':
      return 'video-player';
  }
}

/**
 * Property 6: Message Timestamp Grouping
 * Groups messages by calendar date. Returns groups where all messages
 * within a group share the same calendar date, groups are ordered
 * chronologically, and the label is "Today" for today's date,
 * "Yesterday" for yesterday, or a formatted date string otherwise.
 */
interface MessageGroup {
  date: Date;
  label: string;
  messages: Message[];
}

function getDateLabel(date: Date): string {
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const yesterday = new Date(today.getTime() - 86_400_000);
  const target = new Date(date.getFullYear(), date.getMonth(), date.getDate());

  if (target.getTime() === today.getTime()) return 'Today';
  if (target.getTime() === yesterday.getTime()) return 'Yesterday';

  return date.toLocaleDateString(undefined, {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    year: date.getFullYear() !== now.getFullYear() ? 'numeric' : undefined,
  });
}

function groupMessagesByDate(messages: Message[]): MessageGroup[] {
  if (messages.length === 0) return [];

  const groups: Map<string, Message[]> = new Map();

  for (const message of messages) {
    const date = new Date(message.createdAt);
    const key = `${date.getFullYear()}-${date.getMonth()}-${date.getDate()}`;

    if (!groups.has(key)) {
      groups.set(key, []);
    }
    groups.get(key)!.push(message);
  }

  const result: MessageGroup[] = [];

  for (const [key, msgs] of groups.entries()) {
    const [year, month, day] = key.split('-').map(Number);
    const date = new Date(year, month, day);
    result.push({
      date,
      label: getDateLabel(date),
      messages: msgs,
    });
  }

  // Sort chronologically
  result.sort((a, b) => a.date.getTime() - b.date.getTime());

  return result;
}

/**
 * Property 7: Message Status to Indicator Mapping
 * For any outbound message status, the indicator function should return:
 * single check for SENT, double check for DELIVERED, blue double check for READ,
 * spinner for PENDING, and error icon for FAILED.
 */
function getStatusIndicator(
  status: 'PENDING' | 'SENT' | 'DELIVERED' | 'READ' | 'FAILED'
): 'spinner' | 'check' | 'double-check' | 'double-check-blue' | 'error' {
  switch (status) {
    case 'PENDING':
      return 'spinner';
    case 'SENT':
      return 'check';
    case 'DELIVERED':
      return 'double-check';
    case 'READ':
      return 'double-check-blue';
    case 'FAILED':
      return 'error';
  }
}

/**
 * Property 8: Canned Response Search Filtering
 * For any search query string and set of canned responses, all returned
 * results should contain the query as a case-insensitive substring in
 * either their title or content.
 */
interface CannedResponse {
  id: string;
  title: string;
  content: string;
  shortcut: string;
}

function filterCannedResponses(
  responses: CannedResponse[],
  query: string
): CannedResponse[] {
  if (!query.trim()) return responses;

  const lowerQuery = query.toLowerCase();
  return responses.filter(
    (r) =>
      r.title.toLowerCase().includes(lowerQuery) ||
      r.content.toLowerCase().includes(lowerQuery)
  );
}

/**
 * Property 9: Text Insertion at Cursor Position
 * For any text string, valid cursor position (0 ≤ cursor ≤ text.length),
 * and insertion string, the result should equal text[0..cursor] + insertion + text[cursor..end],
 * preserving all original characters.
 */
function insertTextAtCursor(text: string, cursor: number, insertion: string): string {
  return text.slice(0, cursor) + insertion + text.slice(cursor);
}

/**
 * Property 10: Conversation Search Filtering
 * For any search query and set of conversations, all returned conversations
 * should match the query in at least one of: contact name, message content,
 * or fall within a specified date range.
 */
function filterConversations(
  conversations: Conversation[],
  query: string,
  dateFrom?: string,
  dateTo?: string
): Conversation[] {
  return conversations.filter((conv) => {
    const lowerQuery = query.toLowerCase();

    // Name/content match
    const nameMatch = conv.contactName.toLowerCase().includes(lowerQuery);
    const messageMatch = conv.lastMessage?.toLowerCase().includes(lowerQuery);
    const textMatch = !query.trim() || nameMatch || messageMatch;

    // Date range match
    let dateMatch = true;
    if (dateFrom && conv.lastMessageAt) {
      dateMatch = new Date(conv.lastMessageAt) >= new Date(dateFrom);
    }
    if (dateTo && conv.lastMessageAt) {
      dateMatch = dateMatch && new Date(conv.lastMessageAt) <= new Date(dateTo + 'T23:59:59');
    }

    return textMatch && dateMatch;
  });
}

