/**
 * Agent Builder Utilities
 * Provides core functionality for agent trigger pattern matching and template variable substitution
 */

export type TriggerType = 'keyword' | 'regex' | 'intent';

export interface AgentTrigger {
  id: string;
  type: TriggerType;
  pattern: string;
  priority: number;
}

/**
 * Matches a message against a single trigger pattern
 * Supports keyword (case-insensitive substring), regex, and intent matching
 */
export function matchTrigger(message: string, trigger: AgentTrigger): boolean {
  if (!message || !trigger.pattern) {
    return false;
  }

  try {
    switch (trigger.type) {
      case 'keyword':
        // Case-insensitive substring match
        return message.toLowerCase().includes(trigger.pattern.toLowerCase());

      case 'regex':
        // Regex pattern match with error handling
        try {
          const regex = new RegExp(trigger.pattern, 'i');
          return regex.test(message);
        } catch {
          // Invalid regex pattern - no match
          return false;
        }

      case 'intent':
        // Intent matching: exact match after normalization
        const normalizedMessage = message.toLowerCase().trim();
        const normalizedPattern = trigger.pattern.toLowerCase().trim();
        return normalizedMessage === normalizedPattern;

      default:
        return false;
    }
  } catch {
    return false;
  }
}

/**
 * Finds all triggers that match a given message
 * Returns triggers in priority order (higher priority first)
 */
export function findMatchingTriggers(
  message: string,
  triggers: AgentTrigger[]
): AgentTrigger[] {
  if (!message || !triggers || triggers.length === 0) {
    return [];
  }

  const matching = triggers.filter((trigger) => matchTrigger(message, trigger));

  // Sort by priority descending (higher priority first)
  return matching.sort((a, b) => b.priority - a.priority);
}

/**
 * Substitutes template variables in a template string
 * Replaces {{variable}} placeholders with values from context
 * Leaves unmatched placeholders unchanged
 */
export function substituteTemplateVariables(
  template: string,
  context: Record<string, any>
): string {
  if (!template) {
    return template;
  }

  if (!context || Object.keys(context).length === 0) {
    return template;
  }

  // Replace {{variable}} with context values
  return template.replace(/\{\{(\w+)\}\}/g, (match, key) => {
    if (key in context) {
      const value = context[key];
      // Convert value to string, handling null/undefined
      return value !== null && value !== undefined ? String(value) : match;
    }
    // Leave unmatched placeholders unchanged
    return match;
  });
}

/**
 * Validates a template string for proper placeholder syntax
 * Returns array of variable names found in template
 */
export function extractTemplateVariables(template: string): string[] {
  if (!template) {
    return [];
  }

  const variables: string[] = [];
  const regex = /\{\{(\w+)\}\}/g;
  let match;

  while ((match = regex.exec(template)) !== null) {
    variables.push(match[1]);
  }

  return [...new Set(variables)]; // Remove duplicates
}

/**
 * Checks if all required variables in a template are present in context
 */
export function validateTemplateContext(
  template: string,
  context: Record<string, any>
): { valid: boolean; missingVariables: string[] } {
  const required = extractTemplateVariables(template);
  const missing = required.filter((variable) => !(variable in context));

  return {
    valid: missing.length === 0,
    missingVariables: missing,
  };
}

