    it('should match keyword triggers with case-insensitive substring matching', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          fc.string({ minLength: 1 }),
          (message, keyword) => {
            const trigger: AgentTrigger = {
              id: '1',
              type: 'keyword',
              pattern: keyword,
              priority: 1,
            };

            const result = matchTrigger(message, trigger);
            const expected = message.toLowerCase().includes(keyword.toLowerCase());

            expect(result).toBe(expected);
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should match regex triggers correctly', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          fc.string({ minLength: 1, maxLength: 20 }).filter((s) => {
            // Filter to valid regex patterns
            try {
              new RegExp(s);
              return true;
            } catch {
              return false;
            }
          }),
          (message, pattern) => {
            const trigger: AgentTrigger = {
              id: '1',
              type: 'regex',
              pattern,
              priority: 1,
            };

            const result = matchTrigger(message, trigger);

            // Verify result matches expected regex behavior
            try {
              const regex = new RegExp(pattern, 'i');
              expect(result).toBe(regex.test(message));
            } catch {
              // Invalid regex should not match
              expect(result).toBe(false);
            }
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should match intent triggers with exact normalized matching', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          fc.string({ minLength: 1 }),
          (message, intent) => {
            const trigger: AgentTrigger = {
              id: '1',
              type: 'intent',
              pattern: intent,
              priority: 1,
            };

            const result = matchTrigger(message, trigger);
            const normalizedMessage = message.toLowerCase().trim();
            const normalizedPattern = intent.toLowerCase().trim();
            const expected = normalizedMessage === normalizedPattern;

            expect(result).toBe(expected);
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should return all matching triggers and exclude non-matching ones', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          fc.array(
            fc.record({
              id: fc.string(),
              type: fc.constantFrom<TriggerType>('keyword', 'regex', 'intent'),
              pattern: fc.string({ minLength: 1, maxLength: 20 }),
              priority: fc.integer({ min: 0, max: 100 }),
            }),
            { minLength: 1, maxLength: 10 }
          ),
          (message, triggers) => {
            const result = findMatchingTriggers(message, triggers);

            // Verify all returned triggers match the message
            result.forEach((trigger) => {
              expect(matchTrigger(message, trigger)).toBe(true);
            });

            // Verify no non-matching triggers are returned
            triggers.forEach((trigger) => {
              if (!matchTrigger(message, trigger)) {
                expect(result).not.toContainEqual(trigger);
              }
            });
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should return empty array when no triggers match', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          fc.array(
            fc.record({
              id: fc.string(),
              type: fc.constantFrom<TriggerType>('keyword', 'regex', 'intent'),
              pattern: fc.string({ minLength: 1, maxLength: 20 }),
              priority: fc.integer({ min: 0, max: 100 }),
            }),
            { minLength: 0, maxLength: 10 }
          ),
          (message, triggers) => {
            const result = findMatchingTriggers(message, triggers);

            // If result is empty, verify no trigger matches
            if (result.length === 0) {
              triggers.forEach((trigger) => {
                expect(matchTrigger(message, trigger)).toBe(false);
              });
            }
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should return triggers sorted by priority (highest first)', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          fc.array(
            fc.record({
              id: fc.string(),
              type: fc.constantFrom<TriggerType>('keyword'),
              pattern: fc.string({ minLength: 1 }),
              priority: fc.integer({ min: 0, max: 100 }),
            }),
            { minLength: 1, maxLength: 10 }
          ),
          (message, triggers) => {
            // Make all triggers match by using keyword type with message content
            const matchingTriggers = triggers.map((t) => ({
              ...t,
              pattern: message.substring(0, Math.max(1, message.length / 2)),
            }));

            const result = findMatchingTriggers(message, matchingTriggers);

            // Verify priority ordering
            for (let i = 1; i < result.length; i++) {
              expect(result[i - 1].priority).toBeGreaterThanOrEqual(result[i].priority);
            }
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should handle empty message gracefully', () => {
      fc.assert(
        fc.property(
          fc.record({
            id: fc.string(),
            type: fc.constantFrom<TriggerType>('keyword', 'regex', 'intent'),
            pattern: fc.string({ minLength: 1 }),
            priority: fc.integer({ min: 0, max: 100 }),
          }),
          (trigger) => {
