  describe('Property 12: Template Variable Substitution', () => {
    /**
     * **Validates: Requirements 8.5**
     *
     * For any template string containing {{variable}} placeholders and a data context object,
     * substitution should replace every placeholder with its corresponding value from the context,
     * and leave the template unchanged where no matching key exists.
     */

    it('should replace all matching placeholders with context values', () => {
      fc.assert(
        fc.property(
          fc.record({
            name: fc.string({ minLength: 1 }),
            email: fc.string({ minLength: 1 }),
            age: fc.integer({ min: 0, max: 150 }),
          }),
          (context) => {
            const template = 'Hello {{name}}, your email is {{email}} and age is {{age}}.';
            const result = substituteTemplateVariables(template, context);

            expect(result).toContain(context.name);
            expect(result).toContain(context.email);
            expect(result).toContain(String(context.age));
            expect(result).not.toContain('{{name}}');
            expect(result).not.toContain('{{email}}');
            expect(result).not.toContain('{{age}}');
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should leave unmatched placeholders unchanged', () => {
      fc.assert(
        fc.property(
          fc.record({
            name: fc.string({ minLength: 1 }),
          }),
          (context) => {
            const template = 'Hello {{name}}, your {{missing}} is unknown.';
            const result = substituteTemplateVariables(template, context);

            expect(result).toContain(context.name);
            expect(result).toContain('{{missing}}'); // Unmatched placeholder unchanged
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should handle empty context by leaving all placeholders unchanged', () => {
      fc.assert(
        fc.property(fc.string({ minLength: 1 }), (template) => {
