          placeholders.forEach((placeholder) => {
            expect(result).toContain(placeholder);
          });
        }),
        { numRuns: 100 }
      );
    });

    it('should handle null and undefined values in context', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          (template) => {
            const context = {
              nullValue: null,
              undefinedValue: undefined,
