            key: fc.string({ minLength: 1 }),
          }),
          (template, context) => {
            const result = substituteTemplateVariables(template, context);
            expect(result).toBe(template);
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should handle multiple occurrences of same placeholder', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1, maxLength: 20 }).filter((s) => !s.includes('{{') && !s.includes('}}') && !s.includes('is') && !s.includes('and')),
          (value) => {
            const template = '{{name}} is {{name}}, and {{name}} again.';
            const context = { name: value };

            const result = substituteTemplateVariables(template, context);

            // All occurrences should be replaced
            expect(result).not.toContain('{{name}}');
            // Verify the template structure is correct
            expect(result).toContain(' is ');
            expect(result).toContain(', and ');
            // Count how many times the value appears (should be exactly 3)
            const parts = result.split(value);
            expect(parts.length).toBe(4); // 3 occurrences create 4 parts
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should handle numeric and boolean values in context', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: -1000, max: 1000 }),
          fc.boolean(),
          (num, bool) => {
            const template = 'Number: {{num}}, Boolean: {{bool}}';
            const context = { num, bool };

            const result = substituteTemplateVariables(template, context);

            expect(result).toContain(String(num));
            expect(result).toContain(String(bool));
            expect(result).not.toContain('{{num}}');
            expect(result).not.toContain('{{bool}}');
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should handle empty template', () => {
      fc.assert(
        fc.property(
          fc.record({
            key: fc.string({ minLength: 1 }),
          }),
          (context) => {
            const result = substituteTemplateVariables('', context);
            expect(result).toBe('');
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should handle special characters in placeholder values', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1 }),
          (value) => {
            const template = 'Value: {{data}}';
            const context = { data: value };

            const result = substituteTemplateVariables(template, context);

            expect(result).toContain(value);
            expect(result).not.toContain('{{data}}');
          }
        ),
        { numRuns: 100 }
      );
    });
  });

  describe('Helper Functions', () => {
    describe('extractTemplateVariables', () => {
      it('should extract all unique variable names from template', () => {
        fc.assert(
          fc.property(
            fc.array(fc.string({ minLength: 1, maxLength: 10 }).filter((s) => /^\w+$/.test(s)), {
              minLength: 1,
              maxLength: 5,
            }),
            (variables) => {
              const template = variables.map((v) => `{{${v}}}`).join(' ');
              const result = extractTemplateVariables(template);

              // Should contain all unique variables
              const uniqueVars = [...new Set(variables)];
              expect(result.length).toBe(uniqueVars.length);
              uniqueVars.forEach((v) => {
                expect(result).toContain(v);
              });
            }
          ),
          { numRuns: 100 }
        );
      });

      it('should return empty array for template without placeholders', () => {
        fc.assert(
          fc.property(
            fc.string({ minLength: 1 }).filter((s) => !s.includes('{{')),
            (template) => {
              const result = extractTemplateVariables(template);
              expect(result).toEqual([]);
            }
          ),
          { numRuns: 100 }
        );
      });
    });

    describe('validateTemplateContext', () => {
      it('should validate that all required variables are present in context', () => {
        fc.assert(
          fc.property(
            fc.array(fc.string({ minLength: 1, maxLength: 10 }).filter((s) => /^\w+$/.test(s)), {
              minLength: 1,
              maxLength: 5,
            }),
            (variables) => {
              const template = variables.map((v) => `{{${v}}}`).join(' ');
              const context = Object.fromEntries(
                variables.map((v) => [v, 'value'])
              );

              const result = validateTemplateContext(template, context);

              expect(result.valid).toBe(true);
              expect(result.missingVariables).toEqual([]);
            }
          ),
          { numRuns: 100 }
        );
      });

      it('should identify missing variables in context', () => {
        fc.assert(
          fc.property(
            fc.array(fc.string({ minLength: 1, maxLength: 10 }).filter((s) => /^[a-zA-Z_]\w*$/.test(s)), {
              minLength: 1,
              maxLength: 5,
            }),
            (variables) => {
              const template = variables.map((v) => `{{${v}}}`).join(' ');
              // Use Object.create(null) to avoid prototype properties
              const context = Object.create(null);

              const result = validateTemplateContext(template, context);

              expect(result.valid).toBe(false);
              const uniqueVars = [...new Set(variables)];
              expect(result.missingVariables.length).toBe(uniqueVars.length);
            }
          ),
          { numRuns: 100 }
        );
      });
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle malformed regex patterns gracefully', () => {
      const trigger: AgentTrigger = {
        id: '1',
        type: 'regex',
        pattern: '[invalid(regex',
        priority: 1,
      };

      expect(() => matchTrigger('test message', trigger)).not.toThrow();
      expect(matchTrigger('test message', trigger)).toBe(false);
    });

    it('should handle very long messages and patterns', () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1000, maxLength: 10000 }),
