            const trigger: AgentTrigger = {
              id: '1',
              type: 'keyword',
              pattern,
              priority: 1,
            };

            expect(() => matchTrigger(message, trigger)).not.toThrow();
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should handle whitespace-only templates', () => {
      const template = '   ';
      const context = { key: 'value' };

      const result = substituteTemplateVariables(template, context);
      expect(result).toBe(template);
    });
  });
});

import fc from 'fast-check';
import {
  WorkflowNode,
  WorkflowConnection,
  WorkflowGraph,
  WorkflowVersion,
  WorkflowNodeType,
  Port,
} from '../../stores/workflow-store';

/**
 * Workflow Utilities Property-Based Tests
 * 
 * These tests validate universal properties that should hold across all valid
 * workflow operations, using property-based testing with fast-check to generate
 * 100+ test cases per property.
 * 
 * **Validates: Requirements 10.2, 10.3, 10.4, 10.5, 10.6, 11.3, 11.5**
 */

// ============================================================================
// Arbitraries (Generators)
// ============================================================================

const nodeTypeArbitrary = (): fc.Arbitrary<WorkflowNodeType> =>
  fc.oneof(
    fc.constant('trigger' as WorkflowNodeType),
    fc.constant('condition' as WorkflowNodeType),
    fc.constant('action' as WorkflowNodeType),
    fc.constant('delay' as WorkflowNodeType),
    fc.constant('split' as WorkflowNodeType),
    fc.constant('merge' as WorkflowNodeType),
    fc.constant('end' as WorkflowNodeType)
  );

const positionArbitrary = (): fc.Arbitrary<{ x: number; y: number }> =>
  fc.record({
    x: fc.integer({ min: -1000, max: 1000 }),
    y: fc.integer({ min: -1000, max: 1000 }),
  });

const portArbitrary = (id: string): fc.Arbitrary<Port> =>
  fc.record({
    id: fc.constant(id),
    label: fc.option(fc.string({ minLength: 1, maxLength: 50 })),
    type: fc.oneof(fc.constant('input' as const), fc.constant('output' as const)),
  });

const workflowNodeArbitrary = (): fc.Arbitrary<WorkflowNode> =>
  fc.tuple(fc.uuid(), nodeTypeArbitrary()).chain(
    ([nodeId, nodeType]) =>
      fc.record({
        id: fc.constant(nodeId),
        type: fc.constant(nodeType),
        label: fc.string({ minLength: 1, maxLength: 50 }),
        description: fc.string({ maxLength: 200 }),
        icon: fc.string({ minLength: 1, maxLength: 20 }),
        position: positionArbitrary(),
        config: fc.dictionary(fc.string({ minLength: 1, maxLength: 20 }), fc.anything()),
        inputPorts: fc.array(
          portArbitrary(fc.sample(fc.uuid(), 1)[0]),
          { maxLength: 3 }
        ),
        outputPorts: fc.array(
          portArbitrary(fc.sample(fc.uuid(), 1)[0]),
          { maxLength: 3 }
        ),
      })
  );

const workflowConnectionArbitrary = (
  sourceNodeId: string,
  targetNodeId: string
): fc.Arbitrary<WorkflowConnection> =>
  fc.record({
    id: fc.string({ minLength: 1, maxLength: 20 }),
    sourceNodeId: fc.constant(sourceNodeId),
    sourcePortId: fc.string({ minLength: 1, maxLength: 20 }),
    targetNodeId: fc.constant(targetNodeId),
    targetPortId: fc.string({ minLength: 1, maxLength: 20 }),
  });

const workflowGraphArbitrary = (): fc.Arbitrary<WorkflowGraph> =>
  fc.record({
    id: fc.string({ minLength: 1, maxLength: 20 }),
    name: fc.string({ minLength: 1, maxLength: 100 }),
    nodes: fc.array(workflowNodeArbitrary(), { maxLength: 10 }),
    connections: fc.array(fc.record({
      id: fc.string({ minLength: 1, maxLength: 20 }),
      sourceNodeId: fc.string({ minLength: 1, maxLength: 20 }),
      sourcePortId: fc.string({ minLength: 1, maxLength: 20 }),
      targetNodeId: fc.string({ minLength: 1, maxLength: 20 }),
      targetPortId: fc.string({ minLength: 1, maxLength: 20 }),
    }), { maxLength: 15 }),
    version: fc.integer({ min: 1, max: 100 }),
    isActive: fc.boolean(),
    createdAt: fc.date().map(d => d.toISOString()),
    updatedAt: fc.date().map(d => d.toISOString()),
  });

// ============================================================================
// Helper Functions (Utilities Under Test)
// ============================================================================

/**
 * Add a node to a workflow graph
 */
function addNodeToGraph(
  graph: WorkflowGraph,
  nodeType: WorkflowNodeType,
  position: { x: number; y: number }
): WorkflowGraph {
  const newNode: WorkflowNode = {
    id: `node-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
    type: nodeType,
    label: nodeType.charAt(0).toUpperCase() + nodeType.slice(1),
    description: '',
    icon: nodeType,
    position,
    config: {},
    inputPorts: nodeType !== 'trigger' ? [{ id: `${Date.now()}-in-0`, type: 'input' }] : [],
    outputPorts: nodeType !== 'end' ? [{ id: `${Date.now()}-out-0`, type: 'output' }] : [],
  };
  return {
    ...graph,
    nodes: [...graph.nodes, newNode],
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Create a connection between two nodes
 */
function createConnection(
  graph: WorkflowGraph,
  sourceNodeId: string,
  sourcePortId: string,
  targetNodeId: string,
  targetPortId: string
): WorkflowGraph {
  const newConnection: WorkflowConnection = {
    id: `conn-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
    sourceNodeId,
    sourcePortId,
    targetNodeId,
    targetPortId,
  };
  return {
    ...graph,
    connections: [...graph.connections, newConnection],
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Delete a connection from the graph
 */
function deleteConnectionFromGraph(graph: WorkflowGraph, connectionId: string): WorkflowGraph {
  return {
    ...graph,
    connections: graph.connections.filter(conn => conn.id !== connectionId),
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Get configuration fields for a node type
 */
function getNodeTypeConfigFields(nodeType: WorkflowNodeType): Record<string, string> {
  const schemas: Record<WorkflowNodeType, Record<string, string>> = {
    trigger: { event: 'string', delay: 'number' },
    condition: { operator: 'string', value: 'string', field: 'string' },
    action: { actionType: 'string', payload: 'object' },
    delay: { duration: 'number', unit: 'string' },
    split: { condition: 'string', branches: 'number' },
    merge: { mergeType: 'string' },
    end: { status: 'string' },
  };
  return schemas[nodeType];
}

/**
 * Clamp zoom level to valid range [0.25, 2.0]
 */
function clampZoomLevel(zoom: number): number {
  // Handle NaN by returning default zoom level
  if (isNaN(zoom)) {
    return 1;
  }
  return Math.min(2.0, Math.max(0.25, zoom));
}

/**
 * Append a version to the version history
 */
function appendVersionToHistory(
  versions: WorkflowVersion[],
  graph: WorkflowGraph,
  author: string,
  description?: string
): WorkflowVersion[] {
  const newVersion: WorkflowVersion = {
    id: `version-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
    version: versions.length + 1,
    graph: { ...graph },
    author,
    timestamp: new Date().toISOString(),
    description,
  };
  return [...versions, newVersion];
}

/**
 * Export workflow to JSON string
 */
function exportWorkflowToJson(graph: WorkflowGraph): string {
  return JSON.stringify(graph, null, 2);
}

/**
 * Import workflow from JSON string
 */
function importWorkflowFromJson(json: string): WorkflowGraph | null {
  try {
    return JSON.parse(json) as WorkflowGraph;
  } catch {
    return null;
  }
}

// ============================================================================
// Property Tests
// ============================================================================

describe('Workflow Utilities - Property-Based Tests', () => {
  /**
   * Property 13: Workflow Node Addition
   * 
   * For any workflow graph and new node, adding the node should:
   * - Increase node count by exactly 1
   * - Make the new node exist in the graph
   * - Leave all other nodes unchanged
   * 
   * **Validates: Requirements 10.2**
   */
  it('Property 13: Node addition increases count by 1, new node exists, others unchanged', () => {
    fc.assert(
      fc.property(
        workflowGraphArbitrary(),
        nodeTypeArbitrary(),
        positionArbitrary(),
        (graph, nodeType, position) => {
          const originalCount = graph.nodes.length;
          const originalNodeIds = new Set(graph.nodes.map(n => n.id));

          const updatedGraph = addNodeToGraph(graph, nodeType, position);

          // Count increased by exactly 1
          expect(updatedGraph.nodes.length).toBe(originalCount + 1);

          // New node exists
          const newNodeIds = new Set(updatedGraph.nodes.map(n => n.id));
          expect(newNodeIds.size).toBe(originalCount + 1);

          // All original nodes still exist
          for (const nodeId of originalNodeIds) {
            expect(newNodeIds.has(nodeId)).toBe(true);
          }

          // All original nodes are unchanged
          for (const originalNode of graph.nodes) {
            const updatedNode = updatedGraph.nodes.find(n => n.id === originalNode.id);
            expect(updatedNode).toEqual(originalNode);
          }
        }
      ),
      { numRuns: 100 }
    );
  });

  /**
   * Property 14: Workflow Connection Creation
   * 
   * For any workflow graph and valid connection parameters, creating a connection should:
   * - Increase connection count by exactly 1
   * - Create connection with correct source and target
   * - Leave all other connections unchanged
   * 
   * **Validates: Requirements 10.3**
   */
  it('Property 14: Connection creation increases count by 1, correct source/target, others unchanged', () => {
    fc.assert(
      fc.property(
        workflowGraphArbitrary(),
        fc.string({ minLength: 1, maxLength: 20 }),
        fc.string({ minLength: 1, maxLength: 20 }),
        fc.string({ minLength: 1, maxLength: 20 }),
        fc.string({ minLength: 1, maxLength: 20 }),
        (graph, sourceNodeId, sourcePortId, targetNodeId, targetPortId) => {
          const originalCount = graph.connections.length;
          const originalConnectionIds = new Set(graph.connections.map(c => c.id));

          const updatedGraph = createConnection(
            graph,
            sourceNodeId,
            sourcePortId,
            targetNodeId,
            targetPortId
          );

          // Count increased by exactly 1
          expect(updatedGraph.connections.length).toBe(originalCount + 1);

          // New connection has correct source and target
          const newConnection = updatedGraph.connections[updatedGraph.connections.length - 1];
          expect(newConnection.sourceNodeId).toBe(sourceNodeId);
          expect(newConnection.sourcePortId).toBe(sourcePortId);
          expect(newConnection.targetNodeId).toBe(targetNodeId);
          expect(newConnection.targetPortId).toBe(targetPortId);

          // All original connections still exist
          const newConnectionIds = new Set(updatedGraph.connections.map(c => c.id));
          for (const connId of originalConnectionIds) {
            expect(newConnectionIds.has(connId)).toBe(true);
          }

          // All original connections are unchanged
          for (const originalConn of graph.connections) {
            const updatedConn = updatedGraph.connections.find(c => c.id === originalConn.id);
            expect(updatedConn).toEqual(originalConn);
          }
        }
      ),
      { numRuns: 100 }
    );
  });

  /**
   * Property 15: Workflow Node Type to Configuration Fields
   * 
   * For any node type, the configuration schema should:
   * - Be non-empty (have at least one field)
   * - Contain type-specific fields appropriate to the node type
   * 
   * **Validates: Requirements 10.4**
   */
  it('Property 15: Node type to config fields mapping is non-empty and type-specific', () => {
    fc.assert(
      fc.property(nodeTypeArbitrary(), (nodeType) => {
        const configFields = getNodeTypeConfigFields(nodeType);

        // Schema is non-empty
        expect(Object.keys(configFields).length).toBeGreaterThan(0);

        // All values are valid field types
        const validTypes = ['string', 'number', 'boolean', 'object', 'array'];
        for (const fieldType of Object.values(configFields)) {
          expect(validTypes).toContain(fieldType);
        }

        // Type-specific validation
        if (nodeType === 'trigger') {
          expect(configFields).toHaveProperty('event');
        } else if (nodeType === 'condition') {
          expect(configFields).toHaveProperty('operator');
          expect(configFields).toHaveProperty('value');
        } else if (nodeType === 'action') {
          expect(configFields).toHaveProperty('actionType');
        } else if (nodeType === 'delay') {
          expect(configFields).toHaveProperty('duration');
        } else if (nodeType === 'split') {
          expect(configFields).toHaveProperty('condition');
        } else if (nodeType === 'merge') {
          expect(configFields).toHaveProperty('mergeType');
        } else if (nodeType === 'end') {
          expect(configFields).toHaveProperty('status');
        }
      }),
      { numRuns: 100 }
    );
  });

  /**
   * Property 16: Zoom Level Clamping
   * 
   * For any zoom value, clamping should:
   * - Always return a value within [0.25, 2.0] bounds
   * - Return the input if already within bounds
   * - Return 0.25 if input is below minimum
   * - Return 2.0 if input is above maximum
   * 
   * **Validates: Requirements 10.5**
   */
  it('Property 16: Zoom level clamping keeps value within [0.25, 2.0] bounds', () => {
    fc.assert(
      fc.property(fc.float({ min: -1000, max: 1000 }), (zoom) => {
        const clamped = clampZoomLevel(zoom);

        // Always within bounds (or default for NaN)
        if (isNaN(zoom)) {
          expect(clamped).toBe(1);
        } else {
          expect(clamped).toBeGreaterThanOrEqual(0.25);
          expect(clamped).toBeLessThanOrEqual(2.0);

          // Correct clamping behavior
          if (zoom < 0.25) {
            expect(clamped).toBe(0.25);
          } else if (zoom > 2.0) {
            expect(clamped).toBe(2.0);
          } else {
            expect(clamped).toBe(zoom);
          }
        }
      }),
      { numRuns: 100 }
    );
  });

  /**
   * Property 17: Workflow Connection Deletion
   * 
   * For any workflow graph and connection ID, deleting a connection should:
   * - Decrease connection count by exactly 1 (if connection exists)
   * - Remove the specified connection
   * - Leave all other connections unchanged
   * 
   * **Validates: Requirements 10.6**
   */
  it('Property 17: Connection deletion decreases count by 1, deleted gone, others unchanged', () => {
    fc.assert(
      fc.property(workflowGraphArbitrary(), (graph) => {
        // Only test if graph has connections
        if (graph.connections.length === 0) {
          return;
        }

        const connectionToDelete = graph.connections[0];
        const originalCount = graph.connections.length;
        const originalConnectionIds = new Set(graph.connections.map(c => c.id));

        const updatedGraph = deleteConnectionFromGraph(graph, connectionToDelete.id);

        // Count decreased by exactly 1
        expect(updatedGraph.connections.length).toBe(originalCount - 1);

        // Deleted connection is gone
        const newConnectionIds = new Set(updatedGraph.connections.map(c => c.id));
        expect(newConnectionIds.has(connectionToDelete.id)).toBe(false);

        // All other connections still exist
        for (const connId of originalConnectionIds) {
          if (connId !== connectionToDelete.id) {
            expect(newConnectionIds.has(connId)).toBe(true);
          }
        }

        // All remaining connections are unchanged
        for (const originalConn of graph.connections) {
          if (originalConn.id !== connectionToDelete.id) {
            const updatedConn = updatedGraph.connections.find(c => c.id === originalConn.id);
            expect(updatedConn).toEqual(originalConn);
          }
        }
      }),
      { numRuns: 100 }
    );
  });

  /**
   * Property 18: Workflow Version History Append
   * 
   * For any version history and new version, appending should:
   * - Increase version count by exactly 1
   * - Append new version at the end
   * - Leave all previous versions unchanged
   * 
   * **Validates: Requirements 11.3**
   */
  it('Property 18: Version history append increases count by 1, ordered by timestamp', () => {
    fc.assert(
      fc.property(
        fc.array(
          fc.record({
            id: fc.uuid(),
            version: fc.integer({ min: 1, max: 100 }),
            graph: workflowGraphArbitrary(),
            author: fc.string({ minLength: 1, maxLength: 50 }),
            timestamp: fc.date().map(d => d.toISOString()),
            description: fc.option(fc.string({ maxLength: 100 })),
          }),
          { maxLength: 10 }
        ),
        workflowGraphArbitrary(),
        fc.string({ minLength: 1, maxLength: 50 }),
        fc.option(fc.string({ maxLength: 100 })),
        (versions, graph, author, description) => {
          const originalCount = versions.length;
          const originalVersionIds = new Set(versions.map(v => v.id));

          const updatedVersions = appendVersionToHistory(versions, graph, author, description);

          // Count increased by exactly 1
          expect(updatedVersions.length).toBe(originalCount + 1);

          // New version is at the end
          const newVersion = updatedVersions[updatedVersions.length - 1];
          expect(newVersion.author).toBe(author);
          if (description !== undefined) {
            expect(newVersion.description).toBe(description);
          }

          // All original versions still exist
          const newVersionIds = new Set(updatedVersions.map(v => v.id));
          for (const versionId of originalVersionIds) {
            expect(newVersionIds.has(versionId)).toBe(true);
          }

          // All original versions are unchanged (compare key fields)
          for (const originalVersion of versions) {
            const updatedVersion = updatedVersions.find(v => v.id === originalVersion.id);
            expect(updatedVersion).toBeDefined();
            if (updatedVersion) {
              expect(updatedVersion.id).toBe(originalVersion.id);
              expect(updatedVersion.version).toBe(originalVersion.version);
              expect(updatedVersion.author).toBe(originalVersion.author);
              expect(updatedVersion.timestamp).toBe(originalVersion.timestamp);
              // Description can be null or undefined, just check they match
              expect(updatedVersion.description ?? null).toBe(originalVersion.description ?? null);
            }
          }

          // New version is appended at the end (not inserted in the middle)
          expect(updatedVersions[updatedVersions.length - 1].id).toBe(newVersion.id);
          
          // All original versions maintain their relative order
          for (let i = 0; i < versions.length; i++) {
            expect(updatedVersions[i].id).toBe(versions[i].id);
          }
        }
      ),
      { numRuns: 100 }
    );
  });

  /**
   * Property 19: Workflow JSON Export/Import Round-Trip
   * 
   * For any workflow graph, exporting to JSON and importing back should:
   * - Produce an equivalent graph (same structure and data)
   * - Preserve all nodes, connections, and metadata
   * - Handle the round-trip without data loss (accounting for JSON serialization)
   * 
   * Note: JSON serialization converts undefined to null, which is expected behavior.
   * 
   * **Validates: Requirements 11.5**
   */
  it('Property 19: JSON export/import round-trip produces equivalent graph', () => {
    fc.assert(
      fc.property(workflowGraphArbitrary(), (originalGraph) => {
        // Export to JSON
        const json = exportWorkflowToJson(originalGraph);

        // Import from JSON
        const importedGraph = importWorkflowFromJson(json);

        // Import succeeded
        expect(importedGraph).not.toBeNull();

        if (importedGraph) {
          // Graphs are equivalent
          expect(importedGraph.id).toBe(originalGraph.id);
          expect(importedGraph.name).toBe(originalGraph.name);
          expect(importedGraph.version).toBe(originalGraph.version);
          expect(importedGraph.isActive).toBe(originalGraph.isActive);

          // Nodes are equivalent (accounting for JSON serialization of undefined → null)
          expect(importedGraph.nodes.length).toBe(originalGraph.nodes.length);
          for (let i = 0; i < originalGraph.nodes.length; i++) {
            const originalNode = originalGraph.nodes[i];
            const importedNode = importedGraph.nodes[i];
            
            expect(importedNode.id).toBe(originalNode.id);
            expect(importedNode.type).toBe(originalNode.type);
            expect(importedNode.label).toBe(originalNode.label);
            expect(importedNode.description).toBe(originalNode.description);
            expect(importedNode.icon).toBe(originalNode.icon);
            expect(importedNode.position).toEqual(originalNode.position);
            expect(importedNode.inputPorts.length).toBe(originalNode.inputPorts.length);
            expect(importedNode.outputPorts.length).toBe(originalNode.outputPorts.length);
          }

          // Connections are equivalent
          expect(importedGraph.connections.length).toBe(originalGraph.connections.length);
          for (let i = 0; i < originalGraph.connections.length; i++) {
            expect(importedGraph.connections[i]).toEqual(originalGraph.connections[i]);
          }

          // Metadata is preserved
          expect(importedGraph.createdAt).toBe(originalGraph.createdAt);
          expect(importedGraph.updatedAt).toBe(originalGraph.updatedAt);
        }
      }),
      { numRuns: 100 }
    );
  });
});

