/**
 * Get error information for a specific channel and error code
 * Property 20: Channel Error to Troubleshooting Mapping
 * - For any channel type and error code, returns non-empty message and steps array
 * - If error code not found, returns a generic error with default steps
 */
export function getChannelErrorInfo(
  channelType: ChannelType,
  errorCode: string
): ChannelErrorInfo {
  const channelErrors = CHANNEL_ERROR_MAPPING[channelType];
  if (!channelErrors) {
    return {
      message: `Unknown error for ${channelType}`,
      steps: ['Contact support for assistance'],
    };
  }

  const errorInfo = channelErrors[errorCode];
  if (!errorInfo) {
    return {
      message: `Unknown error: ${errorCode}`,
      steps: ['Check the error details', 'Contact support if the issue persists'],
    };
  }

  return errorInfo;
}

/**
 * Filter conversations by channel type
 * Property 21: Multi-Channel Aggregation and Filtering
 * - For 'all' filter, returns complete set of conversations
 * - For specific channel type, returns only conversations of that type
 * - Returned subset is always a subset of input conversations
 */
export function filterConversationsByChannel(
  conversations: Conversation[],
  channelFilter: ChannelType | 'all'
): Conversation[] {
  if (channelFilter === 'all') {
    return conversations;
  }
  return conversations.filter((conv) => conv.channel === channelFilter);
}

/**
 * Get the channel type for a reply based on the original conversation
 * Property 22: Reply Routing Through Original Channel
 * - For any conversation, returns the same channel type as the conversation
 * - Ensures replies are sent through the original channel
 */
export function getReplyChannel(conversation: Conversation): ChannelType {
  return conversation.channel;
}

/**
 * Aggregate conversations by channel type
 * Returns a map of channel types to conversation counts
 */
export function aggregateConversationsByChannel(
  conversations: Conversation[]
): Record<ChannelType, number> {
  const channels: ChannelType[] = [
    'whatsapp',
    'telegram',
    'discord',
    'instagram',
    'facebook',
    'email',
  ];

  const result: Record<ChannelType, number> = {} as Record<ChannelType, number>;

  for (const channel of channels) {
    result[channel] = conversations.filter((conv) => conv.channel === channel).length;
  }

  return result;
}

/**
 * Get all unique channel types from conversations
 */
export function getActiveChannels(conversations: Conversation[]): ChannelType[] {
  const channels = new Set<ChannelType>();
  for (const conv of conversations) {
    channels.add(conv.channel);
  }
  return Array.from(channels);
}

/**
 * Validate channel configuration based on type
 */
export function validateChannelConfig(
  channelType: ChannelType,
  config: ChannelConfig
): { valid: boolean; errors: string[] } {
  const errors: string[] = [];

  switch (channelType) {
    case 'telegram': {
      const telegramConfig = config as any;
      if (!telegramConfig.botToken || telegramConfig.botToken.trim() === '') {
        errors.push('Bot token is required');
      }
      if (!telegramConfig.webhookUrl || telegramConfig.webhookUrl.trim() === '') {
        errors.push('Webhook URL is required');
      }
      break;
    }
    case 'discord': {
      const discordConfig = config as any;
      if (!discordConfig.botToken || discordConfig.botToken.trim() === '') {
        errors.push('Bot token is required');
      }
      if (!discordConfig.guildId || discordConfig.guildId.trim() === '') {
        errors.push('Guild ID is required');
      }
      if (!discordConfig.channelId || discordConfig.channelId.trim() === '') {
        errors.push('Channel ID is required');
      }
      break;
    }
    case 'instagram': {
      const instagramConfig = config as any;
      if (!instagramConfig.accessToken || instagramConfig.accessToken.trim() === '') {
        errors.push('Access token is required');
      }
      if (!instagramConfig.pageId || instagramConfig.pageId.trim() === '') {
        errors.push('Page ID is required');
      }
      break;
    }
    case 'facebook': {
      const facebookConfig = config as any;
      if (!facebookConfig.pageAccessToken || facebookConfig.pageAccessToken.trim() === '') {
        errors.push('Page access token is required');
      }
      if (!facebookConfig.pageId || facebookConfig.pageId.trim() === '') {
        errors.push('Page ID is required');
      }
      if (!facebookConfig.appSecret || facebookConfig.appSecret.trim() === '') {
        errors.push('App secret is required');
      }
      break;
    }
    case 'email': {
      const emailConfig = config as any;
      if (!emailConfig.smtpHost || emailConfig.smtpHost.trim() === '') {
        errors.push('SMTP host is required');
      }
      if (!emailConfig.smtpPort || emailConfig.smtpPort <= 0) {
        errors.push('Valid SMTP port is required');
      }
      if (!emailConfig.imapHost || emailConfig.imapHost.trim() === '') {
        errors.push('IMAP host is required');
      }
      if (!emailConfig.imapPort || emailConfig.imapPort <= 0) {
        errors.push('Valid IMAP port is required');
      }
      if (!emailConfig.username || emailConfig.username.trim() === '') {
        errors.push('Username is required');
      }
      if (!emailConfig.password || emailConfig.password.trim() === '') {
        errors.push('Password is required');
      }
      break;
    }
    case 'whatsapp': {
      const whatsappConfig = config as any;
      if (!whatsappConfig.botToken || whatsappConfig.botToken.trim() === '') {
        errors.push('Bot token is required');
      }
      if (!whatsappConfig.webhookUrl || whatsappConfig.webhookUrl.trim() === '') {
        errors.push('Webhook URL is required');
      }
      break;
    }
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

import fc from 'fast-check';
import {
  getChannelErrorInfo,
  filterConversationsByChannel,
  getReplyChannel,
  aggregateConversationsByChannel,
  getActiveChannels,
