  type ChannelErrorInfo,
} from '../../utils/channels';
import type { Conversation, ChannelType } from '../../stores/inbox-store';
import type { ChannelConfig } from '../../stores/channel-store';

/**
 * Arbitraries for property-based testing
 */

const channelTypeArbitrary = fc.oneof(
  fc.constant('whatsapp' as ChannelType),
  fc.constant('telegram' as ChannelType),
  fc.constant('discord' as ChannelType),
  fc.constant('instagram' as ChannelType),
  fc.constant('facebook' as ChannelType),
  fc.constant('email' as ChannelType)
);

const errorCodeArbitrary = fc.stringMatching(/^[A-Z_]+$/);

const conversationArbitrary = (channelType?: ChannelType): fc.Arbitrary<Conversation> =>
  fc.record({
    id: fc.uuid(),
    contactId: fc.uuid(),
    contactName: fc.stringMatching(/^[a-zA-Z\s]+$/),
    contactPhone: fc.stringMatching(/^\+?[0-9]{10,15}$/),
    contactAvatar: fc.option(fc.webUrl()),
    channel: channelType ? fc.constant(channelType) : channelTypeArbitrary,
