/**
 * Property 20: Channel Error to Troubleshooting Mapping
 * For any channel type and error code, returns non-empty message and steps array
 * Validates: Requirements 12.5, 13.1, 13.2, 13.3
 */
describe('Property 20: Channel Error to Troubleshooting Mapping', () => {
  it('should return non-empty message and steps for any channel and error code', () => {
    fc.assert(
      fc.property(channelTypeArbitrary, errorCodeArbitrary, (channelType, errorCode) => {
        const result = getChannelErrorInfo(channelType, errorCode);

        // Message should be non-empty
        expect(result.message).toBeTruthy();
        expect(typeof result.message).toBe('string');
        expect(result.message.length).toBeGreaterThan(0);

        // Steps should be a non-empty array
        expect(Array.isArray(result.steps)).toBe(true);
        expect(result.steps.length).toBeGreaterThan(0);

        // Each step should be a non-empty string
        result.steps.forEach((step) => {
          expect(typeof step).toBe('string');
          expect(step.length).toBeGreaterThan(0);
        });
      }),
      { numRuns: 100 }
    );
  });

  it('should return consistent results for the same channel and error code', () => {
    fc.assert(
      fc.property(channelTypeArbitrary, errorCodeArbitrary, (channelType, errorCode) => {
        const result1 = getChannelErrorInfo(channelType, errorCode);
        const result2 = getChannelErrorInfo(channelType, errorCode);

        expect(result1.message).toBe(result2.message);
        expect(result1.steps).toEqual(result2.steps);
      }),
      { numRuns: 100 }
    );
  });

  it('should return known error info for known channel errors', () => {
    const knownErrors = [
      { channel: 'telegram' as ChannelType, code: 'INVALID_TOKEN' },
      { channel: 'discord' as ChannelType, code: 'INVALID_GUILD' },
      { channel: 'instagram' as ChannelType, code: 'API_LIMIT' },
      { channel: 'facebook' as ChannelType, code: 'WEBHOOK_VERIFICATION' },
      { channel: 'email' as ChannelType, code: 'SMTP_AUTH_FAILED' },
      { channel: 'whatsapp' as ChannelType, code: 'INVALID_PHONE' },
    ];

    knownErrors.forEach(({ channel, code }) => {
      const result = getChannelErrorInfo(channel, code);
      expect(result.message).toBeTruthy();
      expect(result.steps.length).toBeGreaterThan(0);
      // Known errors should have specific messages (not generic)
      expect(result.message).not.toContain('Unknown error');
    });
  });

  it('should return fallback error info for unknown error codes', () => {
    const result = getChannelErrorInfo('telegram', 'UNKNOWN_ERROR_CODE_XYZ');
    expect(result.message).toBeTruthy();
    expect(result.steps.length).toBeGreaterThan(0);
    // Should contain "Unknown" for unknown errors
    expect(result.message.toLowerCase()).toContain('unknown');
  });
});

/**
 * Property 21: Multi-Channel Aggregation and Filtering
 * For 'all' filter, returns complete set; for specific channel, returns only that channel
