    first_resolved: {
      title: '🎉 First Resolved!',
      description: 'You have resolved your first conversation. Excellent work!',
    },
    first_workflow: {
      title: '🎉 First Workflow!',
      description: 'You have created your first workflow. Automation unlocked!',
    },
  };

  return metadata[milestone];
}

