  it('should persist and read back the same theme mode', () => {
    // Skip this test in Node.js environment where localStorage is not available
    if (typeof window === 'undefined') {
      expect(true).toBe(true);
      return;
    }

    fc.assert(
      fc.property(arbitraryThemeMode(), (mode: ThemeMode) => {
        // Setup: clear localStorage
        localStorage.clear();

        // Persist the mode
        persistThemePreference(mode);

        // Read it back
        const readMode = readThemePreference();

        // Assert: read mode should equal persisted mode
        expect(readMode).toBe(mode);
      }),
      { numRuns: 100 }
    );
  });

  it('should handle localStorage unavailability gracefully', () => {
    fc.assert(
      fc.property(arbitraryThemeMode(), (mode: ThemeMode) => {
        // This test verifies the function doesn't throw even if localStorage is unavailable
        // In a real environment, we'd mock localStorage, but for now we just verify no throw
        expect(() => {
          persistThemePreference(mode);
        }).not.toThrow();
      }),
      { numRuns: 50 }
    );
  });

  it('should return null when no preference is stored', () => {
    // Skip this test in Node.js environment where localStorage is not available
    if (typeof window === 'undefined') {
      expect(true).toBe(true);
      return;
    }

    localStorage.clear();
    const readMode = readThemePreference();
    expect(readMode).toBeNull();
  });
});

