// Property 27: Toast Type to Visual Mapping
// ============================================================================

describe('Property 27: Toast Type to Visual Mapping', () => {
  /**
   * For any toast type (success, error, warning, info), the visual mapping
   * function should return the correct color scheme (green, red, yellow, blue
   * respectively) and a corresponding icon.
   *
   * Validates: Requirements 16.2
   */
  it('should return correct visual mapping for all toast types', () => {
    fc.assert(
      fc.property(arbitraryToastType(), (type: ToastType) => {
        const mapping = getToastVisualMapping(type);

        // Assert: mapping should have all required properties
        expect(mapping).toHaveProperty('color');
        expect(mapping).toHaveProperty('icon');
        expect(mapping).toHaveProperty('bgColor');
        expect(mapping).toHaveProperty('borderColor');

        // Assert: all properties should be non-empty strings
        expect(typeof mapping.color).toBe('string');
        expect(mapping.color.length).toBeGreaterThan(0);
        expect(typeof mapping.icon).toBe('string');
        expect(mapping.icon.length).toBeGreaterThan(0);
        expect(typeof mapping.bgColor).toBe('string');
        expect(mapping.bgColor.length).toBeGreaterThan(0);
        expect(typeof mapping.borderColor).toBe('string');
        expect(mapping.borderColor.length).toBeGreaterThan(0);
      }),
      { numRuns: 100 }
    );
  });

  it('should map success type to green color', () => {
    const mapping = getToastVisualMapping('success');
    expect(mapping.color).toContain('10b981'); // green hex
    expect(mapping.icon).toBe('check-circle');
  });

  it('should map error type to red color', () => {
    const mapping = getToastVisualMapping('error');
    expect(mapping.color).toContain('ef4444'); // red hex
    expect(mapping.icon).toBe('alert-circle');
  });

  it('should map warning type to yellow color', () => {
    const mapping = getToastVisualMapping('warning');
    expect(mapping.color).toContain('f59e0b'); // yellow hex
    expect(mapping.icon).toBe('alert-triangle');
  });

  it('should map info type to blue color', () => {
    const mapping = getToastVisualMapping('info');
    expect(mapping.color).toContain('3b82f6'); // blue hex
    expect(mapping.icon).toBe('info');
  });

  it('should return consistent mapping for same type', () => {
    fc.assert(
      fc.property(arbitraryToastType(), (type: ToastType) => {
        const mapping1 = getToastVisualMapping(type);
        const mapping2 = getToastVisualMapping(type);

        expect(mapping1).toEqual(mapping2);
      }),
      { numRuns: 100 }
    );
  });

  it('should return different mappings for different types', () => {
    const types: ToastType[] = ['success', 'error', 'warning', 'info'];
    const mappings = types.map((type) => getToastVisualMapping(type));

    // Assert: all mappings should be unique
    const uniqueMappings = new Set(mappings.map((m) => JSON.stringify(m)));
    expect(uniqueMappings.size).toBe(types.length);
  });

  it('should extract toast type correctly from toast object', () => {
    fc.assert(
      fc.property(arbitraryToast(), (toast: Toast) => {
        const extractedType = getToastType(toast);
        expect(extractedType).toBe(toast.type);
      }),
      { numRuns: 100 }
    );
  });
});

