describe('Theme and Notification Integration', () => {
  it('should handle rapid theme changes', () => {
    fc.assert(
      fc.property(fc.array(arbitraryThemeMode(), { minLength: 1, maxLength: 20 }), (modes) => {
        for (const mode of modes) {
          persistThemePreference(mode);
          const resolved = resolveTheme(mode);
          expect(['dark', 'light']).toContain(resolved);
        }
      }),
      { numRuns: 50 }
    );
  });

  it('should handle many toasts with rapid add/remove operations', () => {
    fc.assert(
      fc.property(
        fc.array(arbitraryToast(), { minLength: 10, maxLength: 30 }),
        (toasts) => {
          let state: ToastQueueState = { visible: [], queued: [] };

          // Add toasts
          for (const toast of toasts) {
            state = addToastToQueue(state, toast, 3);
          }

          // Remove toasts in random order
          const allToasts = getAllToasts(state);
          for (const toast of allToasts) {
            state = removeToastFromQueue(state, toast.id, 3);
            expect(validateToastQueue(state, 3)).toBe(true);
          }

          // All should be removed
          expect(state.visible.length).toBe(0);
          expect(state.queued.length).toBe(0);
        }
      ),
      { numRuns: 50 }
    );
  });

  it('should maintain color contrast across all theme changes', () => {
    const darkResult = validateColorContrast('dark', 4.5);
    const lightResult = validateColorContrast('light', 4.5);

    expect(darkResult.valid).toBe(true);
    expect(lightResult.valid).toBe(true);
  });
});
